import React, { Component } from "react";
import Typical from "react-typical";
import Switch from "react-switch";
import { motion } from "framer-motion";

class Header extends Component {
  constructor() {
    super();
    this.state = { checked: false };
    this.onThemeSwitchChange = this.onThemeSwitchChange.bind(this);
  }

  componentDidMount() {
    // Sync switch state with current body theme on load
    const currentTheme = document.body.getAttribute("data-theme");
    this.setState({ checked: currentTheme === "dark" });
  }

  onThemeSwitchChange(checked) {
    this.setState({ checked });
    this.setTheme(checked);
  }

  setTheme(checked) {
    const dataThemeAttribute = "data-theme";
    const body = document.body;
    const newTheme = checked ? "dark" : "light";
    body.setAttribute(dataThemeAttribute, newTheme);
  }

  render() {
    let name = "";
    let titles = [];

    if (this.props.sharedData) {
      name = this.props.sharedData.name;
      titles = this.props.sharedData.titles.map(x => [x.toUpperCase(), 1500]).flat();
    }

    const HeaderTitleTypeAnimation = React.memo(() => {
      return <Typical className="title-styles" steps={titles} loop={50} />
    }, () => true);

    const containerVariants = {
      hidden: { opacity: 0, y: 30 },
      visible: { 
        opacity: 1, 
        y: 0,
        transition: { duration: 0.8, ease: "easeOut", staggerChildren: 0.2 }
      }
    };

    const childVariants = {
      hidden: { opacity: 0, y: 20 },
      visible: { opacity: 1, y: 0 }
    };

    return (
      <header id="home" style={{ 
        height: '100vh', // Changed to vh for better responsiveness
        minHeight: '500px',
        display: 'block',
        background: 'var(--body-background)',
        transition: 'background-color 0.6s ease'
      }}>
        <div className="row aligner" style={{ height: '100%', margin: 0 }}>
          <motion.div 
            className="col-md-12"
            initial="hidden"
            animate="visible"
            variants={containerVariants}
          >
            <div>
              {/* Floating Laptop Icon - Matches Theme Gold */}
              <motion.div
                animate={{ y: [0, -15, 0] }}
                transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
              >
                <span 
                  className="iconify header-icon" 
                  data-icon="la:laptop-code" 
                  data-inline="false"
                  style={{ color: 'var(--header-text)' }}
                ></span>
              </motion.div>

              <br />

              {/* Animated Name - Uses Theme Text */}
              <motion.h1 
                className="mb-0" 
                variants={childVariants}
                style={{ color: 'var(--header-text)', fontWeight: '700' }}
              >
                <Typical steps={[name]} wrapper="p" />
              </motion.h1>

              {/* Animated Titles */}
              <motion.div className="title-container" variants={childVariants}>
                <HeaderTitleTypeAnimation />
              </motion.div>

              {/* Theme Switcher */}
              <motion.div 
                variants={childVariants} 
                style={{ 
                  marginTop: '40px', 
                  width: 'fit-content', 
                  margin: '40px auto 0 auto', 
                  borderRadius: '30px',
                  padding: '6px', 
                  display: 'flex',
                  justifyContent: 'center',
                  background: 'rgba(174,148,79, 0.1)', // Subtle gold glow behind switch
                }} 
                whileHover={{ 
                  scale: 1.05,
                  boxShadow: "0px 0px 20px rgba(174,148,79, 0.3)" 
                }} 
                whileTap={{ scale: 0.95 }}
              >
                <Switch
                  checked={this.state.checked}
                  onChange={this.onThemeSwitchChange}
                  offColor="#baaa80" // Your light theme gold-ish
                  onColor="#353535"  // Your dark theme grey
                  className="react-switch mx-auto"
                  width={90}
                  height={40}
                  uncheckedIcon={
                    <span 
                      className="iconify" 
                      data-icon="twemoji:owl" 
                      style={{ 
                        display: "flex", 
                        alignItems: "center", 
                        justifyContent: "center", 
                        height: "100%", 
                        fontSize: 25,
                        marginLeft: "15px"
                      }}
                    ></span>
                  }
                  checkedIcon={
                    <span 
                      className="iconify" 
                      data-icon="noto-v1:sun-with-face" 
                      style={{ 
                        display: "flex", 
                        alignItems: "center", 
                        justifyContent: "center", 
                        height: "100%", 
                        fontSize: 25,
                        marginLeft: "10px"
                      }}
                    ></span>
                  }
                  id="icon-switch"
                />
              </motion.div>
            </div>
          </motion.div>
        </div>
      </header>
    );
  }
}

export default Header;
